var CheckOpStatus = Class.create();
CheckOpStatus.prototype = Object.extendsObject(AbstractAjaxProcessor, {
    getOperationalStatus: function(ip_address) {
        var result = [];
        var relGr = new GlideRecord('cmdb_rel_ci');
        // Ensure the query string correctly concatenates the IP address
        var queryString = "type=d93304fb0a0a0b78006081a72ef08444^child.ip_address=" + ip_address; // match your condition
