function onSubmit() {
    // Prevent form from submitting if validation hasn't passed yet
    if (!validationPassed) {
        // Perform the check only if validation hasn't passed yet
        var ip_address = g_form.getValue('select_server');
        if (ip_address) {
            // Making an asynchronous call to our Script Include
            var ga = new GlideAjax('CheckOpStatus');
            ga.addParam('sysparm_name', 'getParentNames');
            ga.addParam('sysparm_ip_address', ip_address);
            ga.getXMLAnswer(handleResponse);
            // Prevent form submission to wait for the AJAX call
            return false;
        }
    }
    // If validation has passed (from previous submission attempt), allow form submission
    return validationPassed;
}

function handleResponse(response) {
    var result = JSON.parse(response);
    if (result && result.length > 0) {
        var names = result.join(', ');
        alert("Servers operational and tagged to the Physical server: " + names);

        // Clear the selected server field since we found operational servers
        g_form.clearValue('select_server');

        // Reset the validation flag to require another server selection
        validationPassed = false;
    } else {
        // If no operational servers were found or there were no results, allow submission
        validationPassed = true;
        // Programmatically submit the form
        g_form.submit();
    }
}
```

### Implementation Notes:

- This approach first prevents the form submission if the validation hasn't passed yet. If the `select_server` field has a value, it performs an AJAX call to check the operational status of parent servers.
- Once the AJAX call returns, the `handleResponse` function processes the results. If there are operational servers, it shows an alert and clears the `select_server` field while resetting the `validationPassed` flag.
- If the results come back negative for operational servers, it sets the `validationPassed` flag to `true` and programmatically submits the form using `g_form.submit()`.

