    var serverCheckComplete = sessionStorage.getItem('serverCheckComplete') === 'true';
    var serverCheckPassed = sessionStorage.getItem('serverCheckPassed') === 'true';

    if (serverCheckComplete) {
        // Clear sessionStorage items for next time
        sessionStorage.removeItem('serverCheckComplete');
        sessionStorage.removeItem('serverCheckPassed');

        // If the server check has completed, decide to allow submission based on the result
        return serverCheckPassed;
    }

    var selectedServer = g_form.getValue('select_server');
    if (!selectedServer) {
        // If no server is selected, allow the form to submit
        return true;
    }

    // Use getReference to asynchronously fetch the server record
    g_form.getReference('select_server', function(ref) {
        var ip_address = ref.ip_address;
        if (ip_address) {
            var ga = new GlideAjax('CheckOpStatus');
            ga.addParam('sysparm_name', 'getParentNames');
            ga.addParam('sysparm_ip_address', ip_address);
            ga.getXMLAnswer(function(response) {
                sessionStorage.setItem('serverCheckComplete', 'true');

                var operationalServers = JSON.parse(response);
                if (operationalServers.length > 0) {
                    var names = operationalServers.join(', ');
                    alert("Operational Servers: \n" + names);
                    sessionStorage.setItem('serverCheckPassed', 'false');
                } else {
                    alert("No operational servers found.");
                    sessionStorage.setItem('serverCheckPassed', 'true');
                }

                // Manually trigger the form submission now that the check is complete
                if (sessionStorage.getItem('serverCheckPassed') === 'true') {
                    g_form.submit();
                }
            });
        }
    });

    // Prevent form submission to wait for AJAX call
    return false;
}
```

### Explanation:

- This approach uses `sessionStorage` to retain the state across the asynchronous boundary represented by the AJAX call and potential page reloads. It sets flags in `sessionStorage` when the server check completes instead of using in-memory variables.
- Before allowing submission or retrying it with `g_form.submit()`, it checks these flags.
- Make sure to clear the `sessionStorage` items once you've read them to avoid affecting future submissions.

### Testing:

Thoroughly test this solution in your environment to ensure it behaves as expected under various scenarios, including with and without operational servers found, as well as with multiple rapid submissions.

This solution assumes the client browser supports `sessionStorage`, which is a valid assumption for all modern browsers, but something to be aware of if your environment includes very old browsers or non-standard clients.
